#include <vector>
#include <unordered_map>
#include <set>
#include <algorithm>

using namespace std;

class UnionFind {
private:
    vector<long long> parent;
    vector<long long> min_id;
    vector<set<long long>> online_sets;

public:
    UnionFind(long long n) {
        parent.resize(n + 1);
        min_id.resize(n + 1);
        online_sets.resize(n + 1);
        for (long long i = 1; i <= n; ++i) {
            parent[i] = i;
            min_id[i] = i;
            online_sets[i].insert(i);
        }
    }

    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unionSets(long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX == rootY) return;

        if (online_sets[rootX].size() < online_sets[rootY].size()) {
            swap(rootX, rootY);
        }

        parent[rootY] = rootX;
        min_id[rootX] = min(min_id[rootX], min_id[rootY]);
        online_sets[rootX].insert(online_sets[rootY].begin(), online_sets[rootY].end());
        online_sets[rootY].clear();
    }

    long long getMinOnline(long long x) {
        long long root = find(x);
        if (online_sets[root].empty()) {
            return -1;
        }
        return *online_sets[root].begin();
    }

    void setOffline(long long x) {
        long long root = find(x);
        online_sets[root].erase(x);
    }

    void setOnline(long long x) {
        long long root = find(x);
        online_sets[root].insert(x);
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    UnionFind uf(c);
    for (const auto& conn : connections) {
        uf.unionSets(conn[0], conn[1]);
    }

    vector<bool> online(c + 1, true);
    vector<long long> result;

    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long min_online = uf.getMinOnline(x);
                result.push_back(min_online);
            }
        } else if (type == 2) {
            if (online[x]) {
                online[x] = false;
                uf.setOffline(x);
            }
        }
    }

    return result;
}

