```scala
import scala.collection.mutable

class UnionFind(c: Long) {
  private val parent = Array.tabulate(c.toInt + 1)(i => i)
  private val minId = Array.tabulate(c.toInt + 1)(i => i.toLong)
  private val onlineSets = Array.fill(c.toInt + 1)(mutable.TreeSet[Long]())

  for (i <- 1 to c.toInt) {
    onlineSets(i) += i.toLong
  }

  def find(x: Long): Long = {
    if (parent(x.toInt) != x.toInt) {
      parent(x.toInt) = find(parent(x.toInt)).toInt
    }
    parent(x.toInt).toLong
  }

  def unionSets(x: Long, y: Long): Unit = {
    val rootX = find(x)
    val rootY = find(y)
    if (rootX == rootY) return

    if (onlineSets(rootX.toInt).size < onlineSets(rootY.toInt).size) {
      val temp = rootX
      val rootX = rootY
      val rootY = temp
    }

    parent(rootY.toInt) = rootX.toInt
    minId(rootX.toInt) = math.min(minId(rootX.toInt), minId(rootY.toInt))
    onlineSets(rootX.toInt) ++= onlineSets(rootY.toInt)
    onlineSets(rootY.toInt).clear()
  }

  def getMinOnline(x: Long): Long = {
    val root = find(x)
    if (onlineSets(root.toInt).isEmpty) -1
    else onlineSets(root.toInt).min
  }

  def setOffline(x: Long): Unit = {
    val root = find(x)
    onlineSets(root.toInt) -= x
  }

  def setOnline(x: Long): Unit = {
    val root = find(x)
    onlineSets(root.toInt) += x
  }
}

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val uf = new UnionFind(c)
  connections.foreach { conn =>
    uf.unionSets(conn(0), conn(1))
  }

  val online = Array.fill(c.toInt + 1)(true)
  val result = mutable.ArrayBuffer[Long]()

  queries.foreach { query =>
    val tpe = query(0)
    val x = query(1)
    if (tpe == 1) {
      if (online(x.toInt)) {
        result += x
      } else {
        val minOnline = uf.getMinOnline(x)
        result += minOnline
      }
    } else if (tpe == 2) {
      if (online(x.toInt)) {
        online(x.toInt) = false
        uf.setOffline(x)
      }
    }
  }

  result.toArray
}
